import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.LN3EJxkW.js";const b=JSON.parse('{"title":"可验证用户故事","description":"","frontmatter":{"title":"可验证用户故事","stage":"intermediate","direction":"product","tags":["product","prd","user-story","acceptance"]},"headers":[],"relativePath":"02-product/notes/05-prd-expression/03-verifiable-user-stories.md","filePath":"02-product/notes/05-prd-expression/03-verifiable-user-stories.md","lastUpdated":1784542968000}'),i={name:"02-product/notes/05-prd-expression/03-verifiable-user-stories.md"};function l(o,t,n,h,s,p){return e(),d("div",null,[...t[0]||(t[0]=[r(`<h1 id="可验证用户故事-从用户价值到可反驳的完成条件" tabindex="-1">可验证用户故事：从用户价值到可反驳的完成条件 <a class="header-anchor" href="#可验证用户故事-从用户价值到可反驳的完成条件" aria-label="Permalink to &quot;可验证用户故事：从用户价值到可反驳的完成条件&quot;">​</a></h1><p>用户故事用一条短句表达某类主体在某个场景中的目标与价值。它不是需求的全部，也不是开发任务。可验证用户故事必须同时连接问题证据、业务规则、示例、验收条件和发布观察，使团队能判断实现是否真的满足目标。</p><h2 id="一、故事句式的准确边界" tabindex="-1">一、故事句式的准确边界 <a class="header-anchor" href="#一、故事句式的准确边界" aria-label="Permalink to &quot;一、故事句式的准确边界&quot;">​</a></h2><p>常见句式是：作为某类主体，我希望完成某个目标，从而得到某种价值。三个部分分别回答“谁在什么上下文中行动”“需要达成什么结果”“为什么值得做”。句式是组织对话的工具，不是 Scrum 的强制字段，也不能替代流程、状态、权限和非功能约束。</p><h3 id="_1-主体不是泛化的-用户" tabindex="-1">1. 主体不是泛化的“用户” <a class="header-anchor" href="#_1-主体不是泛化的-用户" aria-label="Permalink to &quot;1. 主体不是泛化的“用户”&quot;">​</a></h3><p>主体应当影响规则或结果。例如“组织管理员”和“受邀成员”在邀请功能中拥有不同权限、可见信息和失败恢复。如果两类人行为完全相同，就不必为了格式虚构角色。</p><p>主体不能只写人口属性。年龄或职业只有在确实改变场景和约束时才有意义。B2B 产品常用责任、权限和数据关系定义主体，例如“拥有成员管理权限的工作区管理员”。</p><h3 id="_2-目标描述可观察结果" tabindex="-1">2. 目标描述可观察结果 <a class="header-anchor" href="#_2-目标描述可观察结果" aria-label="Permalink to &quot;2. 目标描述可观察结果&quot;">​</a></h3><p>“点击邀请按钮”是界面操作，“成功邀请尚未加入组织的成员”才是目标。实现可能从按钮改为批量导入或 API，用户目标仍然成立。</p><p>目标也不能无限宽。一个故事若同时包含注册、审核、付款和通知，无法在一次评审中建立清晰完成条件，应按独立价值与状态边界拆分。</p><h3 id="_3-价值说明结果为何重要" tabindex="-1">3. 价值说明结果为何重要 <a class="header-anchor" href="#_3-价值说明结果为何重要" aria-label="Permalink to &quot;3. 价值说明结果为何重要&quot;">​</a></h3><p>“为了提升体验”无法验证。价值可连接时间、错误、风险、收入或任务成功，例如“减少管理员逐个录入账号的时间”。价值假设需要发布指标验证，验收测试只能证明功能行为，不证明市场效果。</p><h2 id="二、可验证性的五层证据链" tabindex="-1">二、可验证性的五层证据链 <a class="header-anchor" href="#二、可验证性的五层证据链" aria-label="Permalink to &quot;二、可验证性的五层证据链&quot;">​</a></h2><div class="language-mermaid vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P[&quot;问题证据&quot;] --&gt; S[&quot;用户故事&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    S --&gt; R[&quot;业务规则&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    R --&gt; E[&quot;具体示例&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; A[&quot;验收测试&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; O[&quot;发布观察&quot;]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>问题证据证明值得解决；故事确定主体、目标和价值；规则说明允许与禁止；示例把抽象规则放入具体数据；验收测试判断实现；发布观察检验价值假设。任意一层缺失都会产生不同风险。</p><table tabindex="0"><thead><tr><th>层</th><th>典型输入</th><th>可验证输出</th><th>不能替代</th></tr></thead><tbody><tr><td>问题证据</td><td>日志、工单、任务数据</td><td>基线、受影响主体、频率</td><td>实现验收</td></tr><tr><td>用户故事</td><td>场景与目标</td><td>可讨论的价值切片</td><td>完整规则</td></tr><tr><td>业务规则</td><td>权限、状态、计算</td><td>决策表、不变量</td><td>具体示例</td></tr><tr><td>示例</td><td>确切前置与输入</td><td>预期可观察结果</td><td>全部边界集合</td></tr><tr><td>验收测试</td><td>示例与接口</td><td>通过/失败证据</td><td>发布价值</td></tr><tr><td>发布观察</td><td>指标定义与窗口</td><td>效果、护栏、回滚判断</td><td>单次测试</td></tr></tbody></table><h2 id="三、写故事前先确定分析单位" tabindex="-1">三、写故事前先确定分析单位 <a class="header-anchor" href="#三、写故事前先确定分析单位" aria-label="Permalink to &quot;三、写故事前先确定分析单位&quot;">​</a></h2><p>一条故事应围绕一个主体能够独立感知的结果。拆分时使用以下判断：</p><ol><li>结果能否独立发布或隐藏在 feature flag 后。</li><li>是否有独立的成功和失败状态。</li><li>是否能在不依赖另一半未完成逻辑时验收。</li><li>是否改变不同主体或资源的权限。</li><li>是否需要不同的风险、性能或数据约束。</li></ol><p>按技术层拆成“前端故事、接口故事、数据库故事”通常不产生独立用户价值。这些是实现任务，应挂在同一价值故事下。按 CRUD 动词拆分也不总正确：创建草稿与正式提交若有不同状态和价值可以拆；仅把一个表单切成“打开、填写、点击”则不能独立验收。</p><h2 id="四、从业务规则生成验收维度" tabindex="-1">四、从业务规则生成验收维度 <a class="header-anchor" href="#四、从业务规则生成验收维度" aria-label="Permalink to &quot;四、从业务规则生成验收维度&quot;">​</a></h2><p>故事确定范围后，列出会改变结果的维度：</p><ul><li>主体：管理员、普通成员、外部协作者、匿名访问者。</li><li>资源关系：自己的、同组织的、其他组织的、已删除的。</li><li>对象状态：草稿、活动、暂停、归档、处理中。</li><li>输入类别：合法、缺失、重复、超限、格式错误。</li><li>时间：有效期内、边界时刻、过期、时区变化。</li><li>并发：重复提交、旧版本、乱序回调。</li><li>依赖：正常、超时、限流、部分失败。</li></ul><p>维度组合可能很大，不需要穷举笛卡尔积。先覆盖每条业务规则的正例、反例和关键交叉条件；安全、金额、不可逆操作和数据丢失风险需要更强覆盖。</p><h2 id="五、invest-作为评审启发式" tabindex="-1">五、INVEST 作为评审启发式 <a class="header-anchor" href="#五、invest-作为评审启发式" aria-label="Permalink to &quot;五、INVEST 作为评审启发式&quot;">​</a></h2><p>INVEST 常用于检查故事是否 Independent、Negotiable、Valuable、Estimable、Small、Testable。它是启发式，不是自然定律，也不要求故事完全没有依赖。</p><table tabindex="0"><thead><tr><th>项目</th><th>实际检查</th><th>失败信号</th><th>修正</th></tr></thead><tbody><tr><td>Independent</td><td>能否独立排序和验收</td><td>必须等待无关功能</td><td>按价值路径或接口契约解耦</td></tr><tr><td>Negotiable</td><td>是否保留实现讨论空间</td><td>故事直接指定按钮颜色和库</td><td>把必要约束与实现建议分开</td></tr><tr><td>Valuable</td><td>主体能否感知结果</td><td>只有重构动作</td><td>关联用户/业务结果或改为技术工作项</td></tr><tr><td>Estimable</td><td>规则和未知是否足够明确</td><td>关键依赖未验证</td><td>建立 spike 或补证据</td></tr><tr><td>Small</td><td>是否能在反馈周期内完成</td><td>横跨多个流程终态</td><td>按规则、主体或状态拆分</td></tr><tr><td>Testable</td><td>是否有可观察结果</td><td>“更方便”“优化体验”</td><td>写具体示例和阈值</td></tr></tbody></table><h2 id="六、完整案例一-邀请成员" tabindex="-1">六、完整案例一：邀请成员 <a class="header-anchor" href="#六、完整案例一-邀请成员" aria-label="Permalink to &quot;六、完整案例一：邀请成员&quot;">​</a></h2><h3 id="输入事实" tabindex="-1">输入事实 <a class="header-anchor" href="#输入事实" aria-label="Permalink to &quot;输入事实&quot;">​</a></h3><p>工作区管理员当前只能逐个创建账号。过去四周共发起 1,280 次邀请，其中 11% 因邮箱已属于当前工作区而失败，6% 因邀请已存在而重复操作。安全规则要求只有具备 <code>members.invite</code> 能力的主体可邀请。</p><h3 id="故事" tabindex="-1">故事 <a class="header-anchor" href="#故事" aria-label="Permalink to &quot;故事&quot;">​</a></h3><p>作为拥有成员邀请权限的工作区管理员，我希望一次提交多个邮箱并在发送前看到逐项预检结果，从而减少重复操作，同时避免向已有成员或未授权域发送邀请。</p><h3 id="业务规则" tabindex="-1">业务规则 <a class="header-anchor" href="#业务规则" aria-label="Permalink to &quot;业务规则&quot;">​</a></h3><ol><li>服务端对每次请求重新校验主体能力和工作区关系。</li><li>邮箱规范化后在本次输入中去重。</li><li>已是成员的地址不发送邀请，返回 <code>already_member</code>。</li><li>已有未过期邀请的地址返回 <code>pending_invitation</code>。</li><li>组织启用域白名单时，白名单外地址返回 <code>domain_not_allowed</code>。</li><li>单次最多 100 个唯一地址；超过上限不做部分发送。</li><li>发送使用批次幂等键；同一键重复提交返回原批次。</li></ol><h3 id="示例矩阵" tabindex="-1">示例矩阵 <a class="header-anchor" href="#示例矩阵" aria-label="Permalink to &quot;示例矩阵&quot;">​</a></h3><table tabindex="0"><thead><tr><th>权限</th><th>输入</th><th>现有关系</th><th>预检结果</th><th>提交结果</th></tr></thead><tbody><tr><td>有</td><td><a href="mailto:a@example.com" target="_blank" rel="noreferrer">a@example.com</a></td><td>无</td><td>可邀请</td><td>发送一封</td></tr><tr><td>有</td><td><a href="mailto:a@example.com" target="_blank" rel="noreferrer">a@example.com</a>, <a href="mailto:A@example.com" target="_blank" rel="noreferrer">A@example.com</a></td><td>无</td><td>规范化后一个地址</td><td>发送一封</td></tr><tr><td>有</td><td><a href="mailto:member@example.com" target="_blank" rel="noreferrer">member@example.com</a></td><td>已是成员</td><td>already_member</td><td>不发送</td></tr><tr><td>有</td><td><a href="mailto:pending@example.com" target="_blank" rel="noreferrer">pending@example.com</a></td><td>邀请有效</td><td>pending_invitation</td><td>不重复发送</td></tr><tr><td>无</td><td>任意合法邮箱</td><td>无</td><td>不暴露成员关系</td><td>403</td></tr><tr><td>有</td><td>101 个唯一邮箱</td><td>无</td><td>batch_too_large</td><td>整批不发送</td></tr></tbody></table><h3 id="可观察验收" tabindex="-1">可观察验收 <a class="header-anchor" href="#可观察验收" aria-label="Permalink to &quot;可观察验收&quot;">​</a></h3><p>预检返回每个规范化地址的稳定 result code；界面将 code 映射为文案。无权限请求只返回统一拒绝，不泄露某邮箱是否为成员。提交成功返回 batchId、accepted 与 rejected 计数。使用同一幂等键重复请求时 batchId 与计数不变。</p><h3 id="失败注入" tabindex="-1">失败注入 <a class="header-anchor" href="#失败注入" aria-label="Permalink to &quot;失败注入&quot;">​</a></h3><p>让邮件供应商在第 20 个地址后超时。批次记录每项投递状态，重试只处理未确认项；UI 显示处理中而不是整批成功。若无法确认供应商是否接收，状态为 unknown 并通过回调或查询对账。</p><h3 id="发布验证" tabindex="-1">发布验证 <a class="header-anchor" href="#发布验证" aria-label="Permalink to &quot;发布验证&quot;">​</a></h3><p>主指标是每个成功受邀成员对应的管理员操作次数；护栏包括误邀请撤销率、无权限拒绝率、邮件投诉率和批次部分失败率。验收测试通过不代表指标一定改善。</p><h2 id="七、完整案例二-保存筛选器" tabindex="-1">七、完整案例二：保存筛选器 <a class="header-anchor" href="#七、完整案例二-保存筛选器" aria-label="Permalink to &quot;七、完整案例二：保存筛选器&quot;">​</a></h2><p>分析人员每周重复配置订单状态、地区和日期范围。筛选可含个人可见字段，分享时必须重新做字段级权限。</p><p>故事：作为经常分析订单的运营人员，我希望保存一组命名筛选并在之后恢复，从而减少重复配置；在分享筛选时，接收者只能看到自己有权访问的条件和结果。</p><h3 id="拆分决定" tabindex="-1">拆分决定 <a class="header-anchor" href="#拆分决定" aria-label="Permalink to &quot;拆分决定&quot;">​</a></h3><p>“保存个人筛选”与“分享筛选”分成两条故事。保存只影响当前主体，分享新增资源授权、所有者、撤销和字段脱敏，失败边界不同。</p><h3 id="保存故事的验收" tabindex="-1">保存故事的验收 <a class="header-anchor" href="#保存故事的验收" aria-label="Permalink to &quot;保存故事的验收&quot;">​</a></h3><ul><li>名称 trim 后 1–60 个字符，同一主体下重名返回可修正冲突。</li><li>保存的是规范化筛选 schema 和 schemaVersion，不保存当前结果列表。</li><li>已删除字段在恢复时标记 unsupported，不静默改变查询。</li><li>两个标签页基于同一 version 编辑时，旧版本保存返回 409。</li><li>删除筛选后直接打开旧 URL 返回明确不存在并提供返回列表。</li></ul><h3 id="分享故事的验收" tabindex="-1">分享故事的验收 <a class="header-anchor" href="#分享故事的验收" aria-label="Permalink to &quot;分享故事的验收&quot;">​</a></h3><p>分享链接引用稳定 shareId，不在 URL 写完整筛选。服务端每次访问校验 share 状态、接收者、字段能力和租户。所有者撤销后既有链接立即拒绝。接收者无权使用的条件不能仅在前端隐藏。</p><h3 id="失败分支" tabindex="-1">失败分支 <a class="header-anchor" href="#失败分支" aria-label="Permalink to &quot;失败分支&quot;">​</a></h3><p>当 schema 从 v2 升级到 v3，迁移器无法识别旧自定义运算符。恢复结果进入 <code>needs_attention</code>，展示无法应用的条件；不能丢弃该条件后直接查询，因为结果语义已改变。</p><h2 id="八、故事、验收条件与-definition-of-done" tabindex="-1">八、故事、验收条件与 Definition of Done <a class="header-anchor" href="#八、故事、验收条件与-definition-of-done" aria-label="Permalink to &quot;八、故事、验收条件与 Definition of Done&quot;">​</a></h2><p>验收条件属于具体 backlog item，描述该功能在何种条件下可接受。Definition of Done 是团队或产品增量共享的质量标准，例如代码评审、自动化测试、安全扫描、可观测性和发布准备。</p><p>每条故事重复“通过 CI、完成评审”会制造噪音；若某故事有额外安全审计或数据迁移要求，应写成该故事专属验收或交付约束。</p><h2 id="九、故事变更与可追踪性" tabindex="-1">九、故事变更与可追踪性 <a class="header-anchor" href="#九、故事变更与可追踪性" aria-label="Permalink to &quot;九、故事变更与可追踪性&quot;">​</a></h2><p>故事不是签字后冻结的合同。新证据出现时可拆分或改写，但要保留决策链：问题证据、故事 ID、规则版本、场景、测试、发布 flag 和指标。</p><p>需求修改后执行影响分析：哪些 Gherkin 场景失效、接口错误码是否变化、分析事件是否仍能计算指标、旧客户端如何处理新增状态。只改故事文本而不改下游工件，会产生表面一致。</p><h2 id="十、常见不可验证写法" tabindex="-1">十、常见不可验证写法 <a class="header-anchor" href="#十、常见不可验证写法" aria-label="Permalink to &quot;十、常见不可验证写法&quot;">​</a></h2><table tabindex="0"><thead><tr><th>写法</th><th>问题</th><th>修正</th></tr></thead><tbody><tr><td>作为用户，我想要更好的邀请体验</td><td>主体、结果和尺度都不清</td><td>指定管理员、批量预检和减少重复操作</td></tr><tr><td>支持批量邀请</td><td>只有功能名</td><td>补主体、规则、失败和价值</td></tr><tr><td>页面响应要快</td><td>无采样点和阈值</td><td>指定设备、网络、p75/p95 与交互</td></tr><tr><td>用户可以管理筛选</td><td>包含创建、编辑、删除、分享多条链路</td><td>按价值与授权边界拆分</td></tr><tr><td>所有异常正确提示</td><td>异常集合未知</td><td>列出错误分类、可恢复动作和泄露边界</td></tr></tbody></table><h2 id="十一、评审与调试" tabindex="-1">十一、评审与调试 <a class="header-anchor" href="#十一、评审与调试" aria-label="Permalink to &quot;十一、评审与调试&quot;">​</a></h2><p>评审时让产品、设计、开发和测试各自根据故事写出三个具体示例。如果示例对主体、输入或结果理解不同，先修正规则，不急于估算。</p><p>线上出现争议时从失败请求关联回场景：主体能力、资源关系、输入类别、对象状态、规则版本和实际输出。若现有故事无法判断该组合，新增规则与示例，而不是只修一个页面分支。</p><h2 id="十二、综合练习" tabindex="-1">十二、综合练习 <a class="header-anchor" href="#十二、综合练习" aria-label="Permalink to &quot;十二、综合练习&quot;">​</a></h2><p>为“批量导出订单”编写两条独立故事：发起导出和取得结果。覆盖字段权限、数据量上限、异步状态、过期下载、重复发起和部分字段不可用。</p><h3 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h3><ul><li>[ ] 每条故事只有一个可独立感知的结果。</li><li>[ ] 主体由权限或责任定义，不写泛化用户。</li><li>[ ] 业务规则都有正例、反例和可观察输出。</li><li>[ ] 安全边界由服务端验证且不泄露资源存在性。</li><li>[ ] 失败注入包含超时、重复、旧版本和部分失败。</li><li>[ ] 发布指标与验收测试分开，并定义护栏和观察窗口。</li></ul><h2 id="来源" tabindex="-1">来源 <a class="header-anchor" href="#来源" aria-label="Permalink to &quot;来源&quot;">​</a></h2><ul><li><a href="https://cucumber.io/docs/gherkin/reference/" target="_blank" rel="noreferrer">Cucumber：Gherkin Reference</a>（访问日期：2026-07-18）</li><li><a href="https://scrumguides.org/scrum-guide.html" target="_blank" rel="noreferrer">The Scrum Guide 2020</a>（访问日期：2026-07-18）</li><li><a href="https://cheatsheetseries.owasp.org/cheatsheets/Authorization_Cheat_Sheet.html" target="_blank" rel="noreferrer">OWASP Authorization Cheat Sheet</a>（访问日期：2026-07-18）</li><li><a href="https://datatracker.ietf.org/doc/rfc2119/" target="_blank" rel="noreferrer">RFC 2119：Requirement Levels</a>（访问日期：2026-07-18）</li></ul>`,70)])])}const u=a(i,[["render",l]]);export{b as __pageData,u as default};
